import{_ as r,o as t,c as l,ae as e}from"./chunks/framework.BRIUyvy5.js";const _=JSON.parse('{"title":"股癌 每週摘要","description":"","frontmatter":{},"headers":[],"relativePath":"reports/guai/2026-W09.md","filePath":"reports/guai/2026-W09.md"}'),o={name:"reports/guai/2026-W09.md"};function i(n,a,s,g,h,d){return t(),l("div",null,[...a[0]||(a[0]=[e('<h1 id="股癌-每週摘要" tabindex="-1">股癌 每週摘要 <a class="header-anchor" href="#股癌-每週摘要" aria-label="Permalink to &quot;股癌 每週摘要&quot;">​</a></h1><h2 id="_2026-02-25-wed" tabindex="-1">2026-02-25 (Wed) <a class="header-anchor" href="#_2026-02-25-wed" aria-label="Permalink to &quot;2026-02-25 (Wed)&quot;">​</a></h2><p>🎧 股癌 EP639｜2/25(三) 摘要</p><h3 id="_1-市場概況" tabindex="-1">1) 市場概況 <a class="header-anchor" href="#_1-市場概況" aria-label="Permalink to &quot;1) 市場概況&quot;">​</a></h3><ul><li><strong>區域表現兩極化</strong>：台股、日股強勢；美股相對疲弱，科技巨頭/軟體股組合可能輸給 0050 等指數型配置。</li><li><strong>市場結構變化</strong>：相較 2021/2024 高點，較少見新手槓桿/恐慌性行為；聽眾結構偏向長期參與者。</li><li><strong>產業呼吸輪動</strong>：提醒不要因單一區域走強就盲目切換部位；被嫌棄的族群（如晶圓代工/晶片）仍可能輪動回來。</li></ul><h3 id="_2-關注的股票-族群-點名" tabindex="-1">2) 關注的股票 / 族群（點名） <a class="header-anchor" href="#_2-關注的股票-族群-點名" aria-label="Permalink to &quot;2) 關注的股票 / 族群（點名）&quot;">​</a></h3><ul><li><strong>ABF/BT 載板</strong>：欣興(3037)、景碩(3189)</li><li><strong>被動元件</strong>：國巨(2327)、華新科(2492)</li><li><strong>建廠設備與場務</strong>：漢唐(2404)</li><li><strong>太陽能與衛星題材</strong>：元晶(6443)、台郡(6269)</li><li><strong>AI 與高速傳輸</strong>：NVIDIA、Samsung(三星)、貿聯-KY(3665)、群聯(8299)</li><li><strong>美股設備與材料</strong>：Coherent、Lumentum、Astera Labs</li></ul><h3 id="_3-其他財經消息-知識點" tabindex="-1">3) 其他財經消息 / 知識點 <a class="header-anchor" href="#_3-其他財經消息-知識點" aria-label="Permalink to &quot;3) 其他財經消息 / 知識點&quot;">​</a></h3><ul><li><strong>NVIDIA GTC 大會展望</strong>：市場期待新產品驅動股價；傳聞可能整合 Groq 晶片（SRAM 低延遲）或推出 SRAM 堆疊於 CPU 的方案，帶動前端生產需求。</li><li><strong>太陽能產業去中化</strong>：受美國 IRA 法案影響，在地化組件比例要求可能逐步提高至 85%，並限制受外國實體控制材料；非中系供應鏈可能受惠（價格/訂單外溢）。</li><li><strong>電力競爭</strong>：AI 競爭核心在電力；美國面臨變壓器交期長（可達三年）、環評/電網建置瓶頸。</li><li><strong>資訊篩選</strong>：建議過濾 AI 生成的無觀點雜訊，避免「看漲說漲」評論，專注能提供深層邏輯的資訊。</li></ul><h3 id="_4-q-a-觀點" tabindex="-1">4) Q&amp;A / 觀點 <a class="header-anchor" href="#_4-q-a-觀點" aria-label="Permalink to &quot;4) Q&amp;A / 觀點&quot;">​</a></h3><ul><li><strong>進出場策略</strong>：出現大黑K或跌破月線會先減碼（先砍槓桿）；回補偏向右側交易（創新高/站回盤整區間的強勢股），不傾向攤平舊股。</li><li><strong>族群判斷法</strong>：看故事是否具「族群性」；若產業鏈多檔同步上漲，較可能反映基本面支撐。</li><li><strong>投資小生意心態</strong>：投資朋友開的餐廳等中小生意，心態上當作資金不見了；過度查帳易傷和氣。</li><li><strong>Tesla/機器人</strong>：Tesla 純視覺 FSD 仍是標竿；中國機器人發展快，未來可能形成中美兩套市場體系。</li><li><strong>個人健康</strong>：分享肺部結節追蹤無礙；提醒珍惜當下、保持樂觀。</li></ul><hr><h2 id="_2026-02-28-sat" tabindex="-1">2026-02-28 (Sat) <a class="header-anchor" href="#_2026-02-28-sat" aria-label="Permalink to &quot;2026-02-28 (Sat)&quot;">​</a></h2><p>EP640 / 2月28日</p><ol><li><p>市場概況 美股與亞股脫鉤： 目前美股表現相對疲軟，主要受不確定性影響，包含川普關稅政策的潛在衝擊，以及伊朗戰爭風險升溫 。波斯灣地區目前的軍力集結是 2003 年伊拉克戰爭以來最高規模，導致避險情緒增加 。相比之下，台股與日股表現極其強勢，主持人坦言難以用單一邏輯完全解釋亞股的強勁 。 主流切換與觀望： 市場目前缺乏全新的超強主流題材，主要仍由光通訊等相關類股支撐 。主持人建議在不確定性消除前，不宜輕易將部位打滿，應持續觀望市場是否拉出新主流 。 呼吸輪動： 提醒投資者市場存在「呼吸輪動」，不應在行情極端時盲目追高，且應留意長黑 K 出現後的部位調整 。</p></li><li><p>關注的股票 被動元件 (MLCC/電阻/電容)： 族群轉強： 觀察到台股中小型被動元件標的開始集體轉強，顯示族群性正在發酵 。 K 型分化： 高階 AI 伺服器需求極大（單台機櫃 MLCC 用量可達 450 萬顆），而消費級產品仍有壓力 。 轉單契機： 市場傳聞日系大廠（如村田 Murata、TDK）可能退出低階消費性市場，轉向高階 AI 應用，這將為台廠（如 2327 國巨、2492 華新科）帶來中低階市場的缺口與訂單 。 光通訊與高速傳輸： 市場近期全面「買光殺銅」，受 TPU 討論及 NVIDIA GTC 大會預期帶動，光相關標的（如 Coherent、Lumentum、**聯亞 **）估值被推高 。 主持人認為未來仍會是「光銅並行」，他在兩者皆有佈局，但操作上會順應趨勢加碼強勢的光通訊 。 記憶體與 IC 設計： 8299 群聯： 市場關注其向客戶收取「預收款」的通知。主持人傾向解讀為供不應求（利多），類似台積電預收定金換產能的邏輯，而非資金短缺 。 電源供應器： 2308 台達電： 雖然具備太陽能、電動車充電等多重題材，但目前市場估值主要由 AI Data Center（散熱與電源） 驅動，其他題材因營收佔比較小，暫難帶動股價輪動 。 其他美股標的： 提到 Block (SQ) 因裁員與 AI 效率提升故事受關注，以及 Astera Labs 。</p></li><li><p>其他財經消息及知識 Block (Square) 大裁員： Jack Dorsey 宣布裁員 4000 人（約佔一半員工），理由是 AI 提升公司效能 。主持人分析這可能只是「藉口」，核心理由在於公司過去缺乏財務紀律與過度招聘，AI 剛好成為調整結構的台階 。 軟體工程師職缺結構轉變： 數據顯示 2026 年初（應指近期趨勢）軟體職缺年增 11%，但結構已產生質變 。傳統的 CRUD 開發者被洗掉，取而代之的是 AI/ML、資安、資料工程，以及新興的 FDE (Forward Deployment Engineer)，這類職缺結合了工程與 PM/銷售角色，成長率極高 。 太陽能產業「去中化」反饋： 業內人士指出，受美國補貼（稅務抵免）與「去中國化」政策影響，非中系供應鏈（如電池、模組） 確實有結構性獲利機會，但下游受惠程度通常大於上游材料 。 大戶出貨技巧： 提到大戶為避免影響市價，常使用「自動下單」系統（如每 20 秒賣一張），在盤中隱匿蹤跡，這也是為何有時盤後看到大戶跑光，但盤中卻看不出的原因 。</p></li><li><p>Q&amp;A 美股遺產稅避稅： 建議小資族若資產達到一定規模，應諮詢專業會計師 。常見方案包括每年的小額獲利匯回、利用複委託的法律空間，或進行特定的資產配置規避 。 投資標案與水深： 針對聽眾詢問政府標案利潤，主持人認為「水很深」，若標案真的好賺卻沒人搶，通常代表背後有技術門檻或人際網絡等隱形成本 。 低潮與心態： 認為逆境是變強的養分。隨著經驗堆疊，對於市場回檔或事業挫折的調整時間會縮短，應學會從每次「被打倒」中尋找進步的契機 。 指數 ETF 的建議： 持續推薦新手以指數 ETF（如 0050 等）作為入門工具，因為其具備自動汰弱留強的機制，且能讓投資者學習感受市場脈動 。</p></li></ol>',15)])])}const c=r(o,[["render",i]]);export{_ as __pageData,c as default};
